import { CandidApiClient } from "../../../../src/Client";
import { mockServerPool } from "../../../mock-server/MockServerPool";
import { mockOAuthScheme } from "../../mockAuth";

describe("DefaultClient", () => {
    test("get_token", async () => {
        const server = mockServerPool.createServer();
        mockOAuthScheme(server);

        const client = new CandidApiClient({
            maxRetries: 0,
            clientId: "YOUR_CLIENT_ID",
            clientSecret: "YOUR_CLIENT_SECRET",
            environment: { candidApi: server.baseUrl, preEncounter: server.baseUrl },
        });
        const rawRequestBody = { client_id: "YOUR_CLIENT_ID", client_secret: "YOUR_CLIENT_SECRET" };
        const rawResponseBody = { access_token: "eyJz93a...k4laUWw", expires_in: 86400, token_type: "Bearer" };
        server
            .mockEndpoint()
            .post("/api/auth/v2/token")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.auth.default.getToken({
            clientId: "YOUR_CLIENT_ID",
            clientSecret: "YOUR_CLIENT_SECRET",
        });
        expect(response).toEqual({
            body: {
                accessToken: "eyJz93a...k4laUWw",
                expiresIn: 86400,
                tokenType: "Bearer",
            },
            ok: true,
            headers: expect.any(Object),
            rawResponse: expect.any(Object),
        });
    });
});
